import { Link } from "react-router-dom";

export const Navbar = () => {
    return(
        <div className="navbar">
            <h1>Spotify Compare</h1>
            <div className="">
                <Link to="/" >Home</Link>
            <Link to="/login">Login</Link>
            <Link to="/songs" >Songs</Link>
            <Link to="/search" >Search</Link>
            </div>
            
        </div>
    );
}
